// Season data is derived from GAME_LOG once it loads, by rebuildDerived().
// These start empty and are populated when installGameLog() runs on mount.
let DATA = [];
let TEAMS = [];
// The six active 2026 franchises, in display order. Used by the Teams hub.
const TEAMS_2026 = ["SAC", "PDF", "MOD", "SJO", "HAY", "PLE"];
let YEARS = [];
let LEADERS_BY_YEAR = {};

// The most recent season present in the game log. YEARS is rebuilt after the log
// loads, so read this at render time, not at module load.
const currentYear = () => YEARS[YEARS.length - 1];

// Row highlight for leaderboard entries from the current season. Borders on these
// lists already mean championship / playoff / triple-double, so tint the row instead.
const CURRENT_ROW_BG = "bg-blue-50/50";
const CURRENT_YEAR_TEXT = "text-blue-600";

// Game-by-game data: [player, team, opp, week, date, type(R/P/C), gm, pts, reb, stl, ast, blk, fgm, fga, ftm, fta, tpm, tpa, foul, gmSc]
// Game log data is loaded from Supabase at app start (see AppLoader below)
// and stored in this module-scope variable. Columns are positional to match
// legacy code: [0]player [1]team [2]opp [3]week [4]date [5]type [6]g [7]pts
// [8]reb [9]stl [10]ast [11]blk [12]fgm [13]fga [14]ftm [15]fta [16]tpm
// [17]tpa [18]foul [19]gmsc [20]year.
let GAME_LOG = [];

// Derived aggregates: per-team-season and per-player-team-season total Game
// Score. Recomputed after GAME_LOG is loaded. Used for the Team Share bonus
// in AI Score. Counts R/P/C games (exhibition excluded) where the player
// played (g === 1), all GmSc values including negatives.
let TEAM_GMSC_BY_YEAR = {};
let PLAYER_GMSC_BY_TEAM_YEAR = {};

// Game types that count toward season and career totals. Exhibition (X) is
// excluded everywhere totals are formed, including the AI Score share bonus.
const COUNTED_GAME_TYPES = new Set(["R", "P", "C"]);

