// Anonymous placeholder rows (test entries, jersey-only) collapse into one
// "{year} {team} Guest" bucket. Named guests keep "GUEST LASTNAME FIRSTNAME".
function isAnonymousGuest(name) {
  return /^PLAYER\b.*Guest$/i.test(name) || /^#\d+$/.test(name);
}

// Resolve a player's age for a season from AGE_MAP { player: {year:age} }.
// For a year not listed, carry the nearest known age by the year difference
// (age is taken as of Aug 31, so it steps by one per year).
function makeAgeResolver(ageMap) {
  return (player, year) => {
    const byYear = ageMap[player];
    if (!byYear) return null;
    if (year in byYear) return byYear[year];
    let best = null, bestDist = Infinity;
    for (const y in byYear) {
      const yy = +y, d = Math.abs(yy - year);
      if (d < bestDist) { bestDist = d; best = [yy, byYear[y]]; }
    }
    return best ? best[1] + (year - best[0]) : null;
  };
}

// Derive per-player-team-season aggregates from the game log. game_log is the
// single source of truth. Counts R/P/C games where the player played (g===1);
// exhibition is excluded. Output rows match the legacy DATA object shape so
// every downstream consumer (AI Score, awards, leaders) is unchanged.
function buildSeasonData(gameLog) {
  const resolveAge = makeAgeResolver(AGE_MAP);
  const r1 = n => Math.round(n * 10) / 10;
  const r3 = n => Math.round(n * 1000) / 1000;
  const groups = new Map();
  for (const row of gameLog) {
    if (row[6] !== 1) continue;
    if (!COUNTED_GAME_TYPES.has(row[5])) continue;
    const player = row[0], team = row[1], year = row[20];
    const key = player + "|" + team + "|" + year;
    let a = groups.get(key);
    if (!a) {
      a = { player, team, year, g: 0, pts: 0, reb: 0, stl: 0, ast: 0, blk: 0,
        fgm: 0, fga: 0, ftm: 0, fta: 0, tpm: 0, tpa: 0, foul: 0, gmSc: 0 };
      groups.set(key, a);
    }
    a.g += 1;
    a.pts += row[7]; a.reb += row[8]; a.stl += row[9]; a.ast += row[10];
    a.blk += row[11]; a.fgm += row[12]; a.fga += row[13]; a.ftm += row[14];
    a.fta += row[15]; a.tpm += row[16]; a.tpa += row[17]; a.foul += row[18];
    a.gmSc += row[19];
  }
  const out = [];
  for (const a of groups.values()) {
    const g = a.g || 0;
    out.push({
      player: a.player, team: a.team, year: a.year, g, age: resolveAge(a.player, a.year),
      pts: a.pts, reb: a.reb, stl: a.stl, ast: a.ast, blk: a.blk,
      fgm: a.fgm, fga: a.fga, ftm: a.ftm, fta: a.fta, tpm: a.tpm, tpa: a.tpa, foul: a.foul,
      ppg: g ? r1(a.pts / g) : 0, rpg: g ? r1(a.reb / g) : 0, spg: g ? r1(a.stl / g) : 0,
      apg: g ? r1(a.ast / g) : 0, bpg: g ? r1(a.blk / g) : 0,
      fgPct: a.fga ? r3(a.fgm / a.fga) : 0, ftPct: a.fta ? r3(a.ftm / a.fta) : 0,
      tpPct: a.tpa ? r3(a.tpm / a.tpa) : 0, award: "",
      ts: (a.fga || a.fta) ? r3(a.pts / (2 * (a.fga + 0.44 * a.fta))) : 0,
      gmSc: r1(a.gmSc), avgGmSc: g ? r1(a.gmSc / g) : 0,
    });
  }
  return out;
}

// Populate GAME_LOG from a loaded array and rebuild everything derived from it.
// Called once on mount from AppLoader after loadGameLog() resolves. Normalizes
// names and teams in place (alias merges, guest naming, 2018 MCS consolidation,
// Bassem's 2005 Hayward fix), rebuilds the GmSc aggregates, then derives DATA.
function installGameLog(rows) {
  rows.forEach(row => {
    const year = row[20];
    // Normalize to upper case: historical names are all caps and PLAYER_MERGE
    // keys are all caps, but live scoring writes mixed case ("ABDELMALAK
    // Simon"). Uppercasing first lets live games merge with career records.
    let name = (row[0] || "").toUpperCase();
    if (isAnonymousGuest(name)) name = year + " " + row[1] + " Guest";
    else if (PLAYER_MERGE[name]) name = PLAYER_MERGE[name];
    row[0] = name;
    if (year === 2018 && (row[1] === "MOD" || row[1] === "CIS")) row[1] = "MCS";
    else if (year === 2005 && name === "BANOUB BASSEM" && row[1] === "SRA") row[1] = "HAY";
    // Recompute per-game Game Score from the box score with the standard
    // formula, overriding the stored gmsc column (inconsistent for ~5% of
    // games). PTS already includes the 2005-2010 automatic free-throw-line
    // points, so they count; only recorded free-throw misses are penalized.
    row[19] = Math.round((
      row[7] + 0.4 * row[12] - 0.7 * row[13] - 0.4 * (row[15] - row[14])
      + 0.5 * row[8] + row[9] + 0.7 * row[10] + 0.7 * row[11] - 0.4 * row[18]
    ) * 10) / 10;
  });
  GAME_LOG = rows;
  TEAM_GMSC_BY_YEAR = {};
  PLAYER_GMSC_BY_TEAM_YEAR = {};
  rows.forEach(row => {
    const player = row[0], team = row[1], g = row[6], gmsc = row[19], year = row[20];
    if (g !== 1 || !COUNTED_GAME_TYPES.has(row[5])) return;
    const teamKey = team + "-" + year;
    TEAM_GMSC_BY_YEAR[teamKey] = (TEAM_GMSC_BY_YEAR[teamKey] || 0) + gmsc;
    const playerKey = player + "-" + team + "-" + year;
    PLAYER_GMSC_BY_TEAM_YEAR[playerKey] = (PLAYER_GMSC_BY_TEAM_YEAR[playerKey] || 0) + gmsc;
  });
  rebuildDerived();
}

