// Get logo for team at a given year (year optional, defaults to current)
const getTeamLogo = (team, year) => {
  // Year parameter is kept for backward compatibility with existing callers
  // but is ignored — every team now uses a single canonical logo regardless
  // of year.
  if (!team) return null;
  if (team === "NOR") return LOGO_CON_HIST; // NOR redirects to CON's logo
  if (team === "SRA") return LOGO_SRA_HIST;
  if (team === "CON") return LOGO_CON_HIST;
  if (TEAM_LOGOS_CURRENT[team]) return TEAM_LOGOS_CURRENT[team];
  return null;
};

// Franchise mapping: some historical team codes are treated as the same
// franchise as a current team for counting purposes. NOR -> CON (2005 code
// for Sacramento/Concord area). SRA -> PLE (San Ramon became Pleasanton).
// All other codes stay as-is.
const FRANCHISE_MAP = { NOR: "CON", SRA: "PLE" };
const toFranchise = (team) => FRANCHISE_MAP[team] || team;

// Ordinal formatter: 1st, 2nd, 3rd, 4th, ..., 11th, 12th, 13th, ..., 21st, 22nd
const ordinal = (n) => {
  if (n == null) return "";
  const s = ["th", "st", "nd", "rd"];
  const v = n % 100;
  return n + (s[(v - 20) % 10] || s[v] || s[0]);
};

// Back-compat: TEAM_LOGOS[team] returns current logo
const TEAM_LOGOS = new Proxy({}, {
  get: (_, team) => getTeamLogo(team),
});

